namespace sv_3ae4389e2a4b44669e06d04fbb1145bf.Services;

public record TaskItem(int Id, string Title, string Assignee, string Priority, DateTime DueDate, string Status);

public interface ITaskService
{
    Task<List<TaskItem>> GetAllTasksAsync();
    Task<TaskItem> CreateTaskAsync(string title, string assignee, string priority, DateTime dueDate);
    Task UpdateTaskStatusAsync(int taskId, string newStatus);
}

@using sv_3ae4389e2a4b44669e06d04fbb1145bf.Services

<div class="task-card">
    <h4 class="task-title">@Task.Title</h4>
    <p class="task-assignee">@Task.Assignee</p>
    <span class="priority-badge priority-@Task.Priority.ToLowerInvariant()">@Task.Priority</span>
    <span class="task-due-date">@Task.DueDate.ToString("MMM dd")</span>

    <div class="task-actions">
        @if (ShowMoveLeft)
        {
            <button class="btn-move" @onclick="OnMoveLeftClicked">← Move Left</button>
        }
        @if (ShowMoveRight)
        {
            <button class="btn-move" @onclick="OnMoveRightClicked">Move Right →</button>
        }
    </div>
</div>

@code {
    [Parameter, EditorRequired]
    public TaskItem Task { get; set; } = default!;

    [Parameter]
    public bool ShowMoveLeft { get; set; }

    [Parameter]
    public bool ShowMoveRight { get; set; }

    [Parameter]
    public EventCallback OnMoveLeft { get; set; }

    [Parameter]
    public EventCallback OnMoveRight { get; set; }

    private async System.Threading.Tasks.Task OnMoveLeftClicked() => await OnMoveLeft.InvokeAsync();
    private async System.Threading.Tasks.Task OnMoveRightClicked() => await OnMoveRight.InvokeAsync();
}

@using sv_3ae4389e2a4b44669e06d04fbb1145bf.Services

@if (!IsVisible)
{
    <button class="btn-add-task" @onclick="Show">+ Add Task</button>
}
else
{
    <div class="add-task-form">
        <div class="form-field">
            <label>Title</label>
            <input type="text" @bind="title" />
        </div>
        <div class="form-field">
            <label>Assignee</label>
            <input type="text" @bind="assignee" />
        </div>
        <div class="form-field">
            <label>Priority</label>
            <select @bind="priority">
                <option value="High">High</option>
                <option value="Medium">Medium</option>
                <option value="Low">Low</option>
            </select>
        </div>
        <div class="form-field">
            <label>Due Date</label>
            <input type="date" @bind="dueDate" />
        </div>
        <div class="form-actions">
            <button class="btn-save" @onclick="Save" disabled="@isSaving">Save</button>
            <button class="btn-cancel" @onclick="Cancel" disabled="@isSaving">Cancel</button>
        </div>
    </div>
}

@code {
    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    private bool IsVisible;
    private string title = string.Empty;
    private string assignee = string.Empty;
    private string priority = "Medium";
    private DateTime dueDate = DateTime.Today.AddDays(7);
    private bool isSaving;

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    private void Show() => IsVisible = true;

    private void Cancel()
    {
        ResetForm();
        IsVisible = false;
    }

    private async System.Threading.Tasks.Task Save()
    {
        if (string.IsNullOrWhiteSpace(title)) return;

        isSaving = true;
        try
        {
            var created = await TaskService.CreateTaskAsync(title, assignee, priority, dueDate);
            await OnTaskCreated.InvokeAsync(created);
            ResetForm();
            IsVisible = false;
        }
        finally
        {
            isSaving = false;
        }
    }

    private void ResetForm()
    {
        title = string.Empty;
        assignee = string.Empty;
        priority = "Medium";
        dueDate = DateTime.Today.AddDays(7);
    }
}

@using sv_3ae4389e2a4b44669e06d04fbb1145bf.Services

<div class="board-column">
    <div class="column-header">
        <h3>@Status</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="@(ColumnIndex > 0)"
                      ShowMoveRight="@(ColumnIndex < 2)"
                      OnMoveLeft="@(() => MoveTask(task, -1))"
                      OnMoveRight="@(() => MoveTask(task, 1))" />
        }
    </div>

    <AddTaskForm Status="@Status"
                 TaskService="TaskService"
                 OnTaskCreated="OnTaskCreated" />
</div>

@code {
    private static readonly string[] Columns = { "To Do", "In Progress", "Done" };

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnStatusChanged { get; set; }

    private int ColumnIndex => Array.IndexOf(Columns, Status);

    private async System.Threading.Tasks.Task MoveTask(TaskItem task, int direction)
    {
        var newIndex = ColumnIndex + direction;
        if (newIndex < 0 || newIndex >= Columns.Length) return;

        var newStatus = Columns[newIndex];
        await OnStatusChanged.InvokeAsync((task.Id, newStatus));
    }
}

@page "/board"
@using sv_3ae4389e2a4b44669e06d04fbb1145bf.Services
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p class="loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="error-message">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        @foreach (var status in columns)
        {
            <BoardColumn Status="@status"
                         Tasks="@GetFilteredTasks(status)"
                         TaskService="TaskService"
                         OnTaskCreated="HandleTaskCreated"
                         OnStatusChanged="HandleStatusChanged" />
        }
    </div>
}

@code {
    private static readonly string[] columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleStatusChanged((int TaskId, string NewStatus) change)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(change.TaskId, change.NewStatus);
            var task = allTasks.First(t => t.Id == change.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = change.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private Task HandleTaskCreated(TaskItem newTask)
    {
        allTasks.Add(newTask);
        return Task.CompletedTask;
    }
}

.board-columns {
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
}

.loading {
    font-style: italic;
    color: #666;
}

.error-message {
    background: #fee;
    border: 1px solid #c00;
    padding: 1rem;
    border-radius: 4px;
    color: #c00;
}

::deep .board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f5f5f5;
    border-radius: 6px;
    margin-bottom: 1rem;
}

::deep .stat {
    display: flex;
    flex-direction: column;
    align-items: center;
}

::deep .stat-label {
    font-size: 0.75rem;
    text-transform: uppercase;
    color: #666;
}

::deep .stat-value {
    font-size: 1.25rem;
    font-weight: 700;
}

::deep .stat-overdue .stat-value {
    color: #c00;
}

::deep .board-search {
    margin-bottom: 1rem;
}

::deep .board-search input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
}

::deep .board-column {
    flex: 1;
    background: #f0f0f0;
    border-radius: 6px;
    padding: 0.75rem;
    min-width: 250px;
    display: flex;
    flex-direction: column;
}

::deep .column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

::deep .column-header h3 {
    margin: 0;
    font-size: 1rem;
}

::deep .column-count {
    background: #ddd;
    border-radius: 12px;
    padding: 0.1rem 0.5rem;
    font-size: 0.8rem;
    font-weight: 600;
}

::deep .column-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-bottom: 0.75rem;
}

::deep .task-card {
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.75rem;
}

::deep .task-title {
    margin: 0 0 0.25rem;
    font-size: 0.95rem;
}

::deep .task-assignee {
    margin: 0 0 0.5rem;
    font-size: 0.8rem;
    color: #555;
}

::deep .priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    margin-right: 0.5rem;
}

::deep .priority-high {
    background: #fdd;
    color: #c00;
}

::deep .priority-medium {
    background: #ffd;
    color: #a80;
}

::deep .priority-low {
    background: #dfd;
    color: #080;
}

::deep .task-due-date {
    font-size: 0.8rem;
    color: #666;
}

::deep .task-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
}

::deep .btn-move {
    background: #e8e8e8;
    border: 1px solid #ccc;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    font-size: 0.75rem;
    cursor: pointer;
}

::deep .btn-move:hover {
    background: #d0d0d0;
}

::deep .btn-add-task {
    width: 100%;
    padding: 0.5rem;
    background: transparent;
    border: 2px dashed #ccc;
    border-radius: 6px;
    color: #888;
    cursor: pointer;
    font-size: 0.85rem;
}

::deep .btn-add-task:hover {
    border-color: #999;
    color: #555;
}

::deep .add-task-form {
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

::deep .form-field {
    display: flex;
    flex-direction: column;
    gap: 0.2rem;
}

::deep .form-field label {
    font-size: 0.75rem;
    font-weight: 600;
    color: #555;
}

::deep .form-field input,
::deep .form-field select {
    padding: 0.35rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.85rem;
}

::deep .form-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.25rem;
}

::deep .btn-save {
    background: #0070f3;
    color: #fff;
    border: none;
    border-radius: 4px;
    padding: 0.4rem 0.75rem;
    cursor: pointer;
    font-size: 0.85rem;
}

::deep .btn-save:hover {
    background: #005bc1;
}

::deep .btn-cancel {
    background: #e8e8e8;
    border: 1px solid #ccc;
    border-radius: 4px;
    padding: 0.4rem 0.75rem;
    cursor: pointer;
    font-size: 0.85rem;
}

