@using sv_3ae4389e2a4b44669e06d04fbb1145bf.Services

<div class="board-column">
    <div class="column-header">
        <h3>@Status</h3>
        <span class="column-count">@Tasks.Count</span>
    </div>

    <div class="column-body">
        @foreach (var task in Tasks)
        {
            <TaskCard Task="task"
                      ShowMoveLeft="@(ColumnIndex > 0)"
                      ShowMoveRight="@(ColumnIndex < 2)"
                      OnMoveLeft="@(() => MoveTask(task, -1))"
                      OnMoveRight="@(() => MoveTask(task, 1))" />
        }
    </div>

    <AddTaskForm Status="@Status"
                 TaskService="TaskService"
                 OnTaskCreated="OnTaskCreated" />
</div>

@code {
    private static readonly string[] Columns = { "To Do", "In Progress", "Done" };

    [Parameter, EditorRequired]
    public string Status { get; set; } = default!;

    [Parameter, EditorRequired]
    public List<TaskItem> Tasks { get; set; } = new();

    [Parameter, EditorRequired]
    public ITaskService TaskService { get; set; } = default!;

    [Parameter]
    public EventCallback<TaskItem> OnTaskCreated { get; set; }

    [Parameter]
    public EventCallback<(int TaskId, string NewStatus)> OnStatusChanged { get; set; }

    private int ColumnIndex => Array.IndexOf(Columns, Status);

    private async System.Threading.Tasks.Task MoveTask(TaskItem task, int direction)
    {
        var newIndex = ColumnIndex + direction;
        if (newIndex < 0 || newIndex >= Columns.Length) return;

        var newStatus = Columns[newIndex];
        await OnStatusChanged.InvokeAsync((task.Id, newStatus));
    }
}

@page "/board"
@using sv_3ae4389e2a4b44669e06d04fbb1145bf.Services
@rendermode InteractiveServer
@inject ITaskService TaskService

<PageTitle>Kanban Board</PageTitle>

<h1>Kanban Board</h1>

@if (isLoading)
{
    <p class="loading">Loading tasks...</p>
}
else if (errorMessage is not null)
{
    <div class="error-message">
        <p>@errorMessage</p>
        <button @onclick="LoadTasks">Retry</button>
    </div>
}
else
{
    <BoardStats Tasks="allTasks" />
    <BoardSearchBar SearchText="@searchText" OnSearchChanged="HandleSearchChanged" />

    <div class="board-columns">
        @foreach (var status in columns)
        {
            <BoardColumn Status="@status"
                         Tasks="@GetFilteredTasks(status)"
                         TaskService="TaskService"
                         OnTaskCreated="HandleTaskCreated"
                         OnStatusChanged="HandleStatusChanged" />
        }
    </div>
}

@code {
    private static readonly string[] columns = { "To Do", "In Progress", "Done" };

    private List<TaskItem> allTasks = new();
    private string searchText = string.Empty;
    private bool isLoading = true;
    private string? errorMessage;

    protected override async Task OnInitializedAsync()
    {
        await LoadTasks();
    }

    private async Task LoadTasks()
    {
        isLoading = true;
        errorMessage = null;

        try
        {
            allTasks = await TaskService.GetAllTasksAsync();
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to load tasks: {ex.Message}";
        }
        finally
        {
            isLoading = false;
        }
    }

    private List<TaskItem> GetFilteredTasks(string status)
    {
        var tasks = allTasks.Where(t => t.Status == status);

        if (!string.IsNullOrWhiteSpace(searchText))
        {
            tasks = tasks.Where(t => t.Title.Contains(searchText, StringComparison.OrdinalIgnoreCase));
        }

        return tasks.ToList();
    }

    private void HandleSearchChanged(string text)
    {
        searchText = text;
    }

    private async Task HandleStatusChanged((int TaskId, string NewStatus) change)
    {
        try
        {
            await TaskService.UpdateTaskStatusAsync(change.TaskId, change.NewStatus);
            var task = allTasks.First(t => t.Id == change.TaskId);
            var index = allTasks.IndexOf(task);
            allTasks[index] = task with { Status = change.NewStatus };
        }
        catch (Exception ex)
        {
            errorMessage = $"Failed to move task: {ex.Message}";
        }
    }

    private Task HandleTaskCreated(TaskItem newTask)
    {
        allTasks.Add(newTask);
        return Task.CompletedTask;
    }
}

