.board-columns {
    display: flex;
    gap: 1rem;
    margin-top: 1rem;
}

.loading {
    font-style: italic;
    color: #666;
}

.error-message {
    background: #fee;
    border: 1px solid #c00;
    padding: 1rem;
    border-radius: 4px;
    color: #c00;
}

::deep .board-stats {
    display: flex;
    gap: 1.5rem;
    padding: 0.75rem 1rem;
    background: #f5f5f5;
    border-radius: 6px;
    margin-bottom: 1rem;
}

::deep .stat {
    display: flex;
    flex-direction: column;
    align-items: center;
}

::deep .stat-label {
    font-size: 0.75rem;
    text-transform: uppercase;
    color: #666;
}

::deep .stat-value {
    font-size: 1.25rem;
    font-weight: 700;
}

::deep .stat-overdue .stat-value {
    color: #c00;
}

::deep .board-search {
    margin-bottom: 1rem;
}

::deep .board-search input {
    width: 100%;
    max-width: 400px;
    padding: 0.5rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.9rem;
}

::deep .board-column {
    flex: 1;
    background: #f0f0f0;
    border-radius: 6px;
    padding: 0.75rem;
    min-width: 250px;
    display: flex;
    flex-direction: column;
}

::deep .column-header {
    display: flex;
    justify-content: space-between;
    align-items: center;
    margin-bottom: 0.75rem;
}

::deep .column-header h3 {
    margin: 0;
    font-size: 1rem;
}

::deep .column-count {
    background: #ddd;
    border-radius: 12px;
    padding: 0.1rem 0.5rem;
    font-size: 0.8rem;
    font-weight: 600;
}

::deep .column-body {
    flex: 1;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
    margin-bottom: 0.75rem;
}

::deep .task-card {
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.75rem;
}

::deep .task-title {
    margin: 0 0 0.25rem;
    font-size: 0.95rem;
}

::deep .task-assignee {
    margin: 0 0 0.5rem;
    font-size: 0.8rem;
    color: #555;
}

::deep .priority-badge {
    display: inline-block;
    padding: 0.15rem 0.5rem;
    border-radius: 4px;
    font-size: 0.75rem;
    font-weight: 600;
    margin-right: 0.5rem;
}

::deep .priority-high {
    background: #fdd;
    color: #c00;
}

::deep .priority-medium {
    background: #ffd;
    color: #a80;
}

::deep .priority-low {
    background: #dfd;
    color: #080;
}

::deep .task-due-date {
    font-size: 0.8rem;
    color: #666;
}

::deep .task-actions {
    display: flex;
    gap: 0.5rem;
    margin-top: 0.5rem;
}

::deep .btn-move {
    background: #e8e8e8;
    border: 1px solid #ccc;
    border-radius: 4px;
    padding: 0.25rem 0.5rem;
    font-size: 0.75rem;
    cursor: pointer;
}

::deep .btn-move:hover {
    background: #d0d0d0;
}

::deep .btn-add-task {
    width: 100%;
    padding: 0.5rem;
    background: transparent;
    border: 2px dashed #ccc;
    border-radius: 6px;
    color: #888;
    cursor: pointer;
    font-size: 0.85rem;
}

::deep .btn-add-task:hover {
    border-color: #999;
    color: #555;
}

::deep .add-task-form {
    background: #fff;
    border: 1px solid #ddd;
    border-radius: 6px;
    padding: 0.75rem;
    display: flex;
    flex-direction: column;
    gap: 0.5rem;
}

::deep .form-field {
    display: flex;
    flex-direction: column;
    gap: 0.2rem;
}

::deep .form-field label {
    font-size: 0.75rem;
    font-weight: 600;
    color: #555;
}

::deep .form-field input,
::deep .form-field select {
    padding: 0.35rem;
    border: 1px solid #ccc;
    border-radius: 4px;
    font-size: 0.85rem;
}

